import django
from django.conf import settings
settings.configure(
    DATABASES={'default': {'ENGINE': 'django.db.backends.sqlite3', 'NAME': ':memory:'}},
    INSTALLED_APPS=['django.contrib.contenttypes', 'django.contrib.auth'],
)
django.setup()

from django.db.models import Avg, Sum, Min, Max, Count

# Test that Avg, Sum, Min, Max now accept distinct=True
for cls in [Avg, Sum, Min, Max]:
    try:
        agg = cls('x', distinct=True)
        print(f'{cls.__name__} with distinct=True: OK')
    except TypeError as e:
        print(f'{cls.__name__} with distinct=True: FAILED - {e}')

# Test that they still work without distinct
for cls in [Avg, Sum, Min, Max, Count]:
    try:
        agg = cls('x')
        print(f'{cls.__name__} without distinct: OK')
    except Exception as e:
        print(f'{cls.__name__} without distinct: FAILED - {e}')
"
"}

